def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for c in range(1, 15):
                val = np.cos(ratio * c * np.pi) * (c ** 2)
                if c % 4 == 0:
                    val *= 1.15
                else:
                    val *= 0.95 + (ratio * c)/10
                score += val
            if int(capacity) % 2 == 1 and int(item) % 2 == 0:
                score *= 0.75
            if score > 20:
                for j in range(3, 8):
                    score /= np.log1p(j * score)
        elif 0.05 <= ratio < 0.2:
            acc = 1
            for k in range(1, int(capacity // 2) + 3):
                acc *= (1 + (ratio ** k) / (k + 0.5))
                if acc > 5e5:
                    acc = np.sqrt(acc)
                    break
            score += np.tanh(acc) * 40
            for z in range(1, 4):
                score += ((ratio * z * np.e) % 1) * (z * 3.3)
            if (int(capacity) % 5 == 0) or (int(item * 10) % 7 == 0):
                score -= 6.2
            else:
                score += 2.4
            if score < -3:
                score = abs(score) * 1.8 + 1.3
        elif 0.2 <= ratio <= 0.5:
            for n in range(5, 12):
                term = (ratio ** n) * (n ** 3) / ((n + 1) ** 1.2)
                if n % 2 == 0:
                    term *= 1.1
                else:
                    term *= 0.85
                score += term
            diff = capacity - item
            if diff < 5:
                score += 15 - diff * 0.7
            else:
                score -= diff * 1.1
            if score < -7:
                score = abs(score) * 0.4 + 3
            if int(capacity) % 9 == 0:
                score *= 1.3
            if score > 18:
                score /= 2.8
        elif 0.5 < ratio <= 0.75:
            penalty = 0
            for p in range(2, 15):
                pow_term = (ratio - 0.5) ** p
                factor = (p ** 2.2)
                term = pow_term * factor / (np.sqrt(p) + 1)
                if term > 70:
                    term = np.log1p(term) * 2
                penalty += term
            score = penalty * 14
            if capacity < item * 1.1:
                score += 20
            if (int(capacity * 4) % 9 == 0) and (int(item * 7) % 6 == 0):
                score -= 8
            if score < 0:
                score = abs(score) * 1.7 + 4
            if score > 110:
                score = 110
        elif 0.75 < ratio <= 1.25:
            ext_penalty = 0
            diff = ratio - 0.75
            for q in range(1, 14):
                part = (diff ** q) * (q ** 3) / (q + 0.8)
                if part > 1500:
                    part /= np.sqrt(q + 1)
                ext_penalty += part
            score = ext_penalty * 15
            if capacity < item * 1.5:
                score += 25
            if (int(capacity * 2) % 8 == 0) and (int(item * 11) % 3 == 0):
                score -= 10
            for z in range(1, 8):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.3)
            if score < 0:
                score = abs(score) * 0.7
            if score > 1300:
                score = 1300
        else:
            super_penalty = 0
            diff = ratio - 1.25
            for r in range(1, 16):
                term = ((diff) ** r) * (r ** 3.5)
                if term > 15000:
                    term = np.cbrt(term) * 2
                super_penalty += term
            score = super_penalty * 28
            if capacity < item * 2.5:
                score += 30
            if (int(capacity * 11) % 6 == 0) and (int(item * 13) % 7 == 0):
                score -= 12
            for w in range(3, 10):
                score += ((diff / w) % 1) * (w * 3)
            if score < 0:
                score = abs(score) * 0.8 + 5
            if score > 2500:
                score = 2500
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.5)
            score += np.log1p(capacity) * 0.3
        elif capacity < 3:
            score *= 2.8
            if item < 1:
                score *= 1.4
        if abs(score) > 1800:
            score = np.sign(score) * 1800
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        q25, q50, q75 = np.percentile(finite_priorities, [25, 50, 75])
        high_count = np.sum(finite_priorities > q75)
        median_val = q50
        fill_value = np.max(finite_priorities) * (20 + high_count) - median_val * 1.5
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    for k in range(len(priorities)):
        if priorities[k] < 0:
            priorities[k] = abs(priorities[k]) * 0.6 + 2
        if priorities[k] > 1600:
            priorities[k] = 1600
    return priorities
